class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

# Örnek Kullanım:
if __name__ == '__main__':
    trie = Trie()
    trie.insert("apple")
    trie.insert("app")
    trie.insert("apricot")
    trie.insert("banana")

    def search(trie, word):
        node = trie.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    print(search(trie, "apple"))   # True
    print(search(trie, "app"))     # True
    print(search(trie, "ap"))      # False
    print(search(trie, "banana"))  # True
    print(search(trie, "orange"))  # False
